INSERT  IGNORE INTO `content_infos` (`id`, `content_id`, `rid`, `display_name`, `description`, `short_description`, `language_rid`, `created_at`, `updated_at`) VALUES (4,11,'offene-schultern-information-de','Offene Schultern','Diese kurze Einheit mobilisiert deine Schultern und bewegt die Brustwirbelsäule. Effektive Übungen öffnen den Oberkörper und unterstützen dich dabei, deine Haltung bewusster wahrzunehmen.','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-08 10:42:02.516','2026-05-08 10:42:02.516'),(5,12,'stilles-wasser-information-de','Stilles Wasser','Laaang. Laaang. Laaang. Laaang. Laaang. Laaang. Laaang. Laaang. Laaang. Laaang. Laaang. Laaang. Laaang. Laaang. Laaang. ','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 16:19:02.406','2026-05-09 16:19:02.406'),(6,13,'lebensfreude-information-de','Lebensfreude','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 19:58:35.055','2026-05-09 19:58:35.055'),(7,14,'bodyscan-no1-information-de','Bodyscan N°1','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum IpsumLorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 19:59:06.247','2026-05-09 19:59:06.247'),(8,15,'lichtquelle-information-de','Lichtquelle','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 20:04:50.107','2026-05-09 20:04:50.107'),(9,16,'resonanz-information-de','Resonanz','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum IpsumLorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum IpsumLorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 20:08:39.342','2026-05-09 20:08:39.342'),(10,17,'einklang-information-de','Einklang','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 20:13:22.766','2026-05-09 20:13:22.766'),(11,18,'im-moment-information-de','Im Moment','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 20:16:27.518','2026-05-09 20:16:27.518'),(12,19,'verbunden-information-de','Verbunden','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 20:17:35.839','2026-05-09 20:17:35.839'),(13,20,'anspannen-und-loesen-information-de','Anspannen und Lösen','In dieser regenerativen Einheit entspannst du deinen Körper durch bewusstes Anspannen und Atmen. Dein Oberkörper darf dabei Schritt für Schritt weicher werden.','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 20:57:05.484','2026-05-09 20:57:05.484'),(14,21,'bewegung-am-boden-information-de','Bewegung am Boden','Diese ganzheitliche Einheit schult die bewusste Kontrolle deiner Gelenke und verbindet lösende Bewegungen mit Gleichgewichtsübungen. Lockere spürbar Nacken und Rücken und fühle dich freier.','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 20:59:05.432','2026-05-09 20:59:05.432'),(15,22,'tiefer-in-die-beweglichkeit-information-de','Tiefer in die Beweglichkeit','Lass dich in dieser aktiven Einheit mit jeder Runde tiefer in die Beweglichkeit führen. Schule deine Körperwahrnehmung und mobilisiere deinen gesamten Körper.','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 21:01:35.454','2026-05-09 21:01:35.454'),(16,23,'entspannung-ueber-anspannung-information-de','Entspannung über Anspannung','In dieser regenerativen Einheit entspannst du deinen Körper durch bewusstes Anspannen und Atmen. Dein Oberkörper darf dabei Schritt für Schritt weicher werden.','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 21:04:34.227','2026-05-09 21:04:34.227'),(17,24,'weite-flanken-information-de','Weite Flanken','Ein achtsamer Flow, der gezielt deine Körperseiten, Schultern und Mitte mobilisiert und dehnt. Schaffe neuen Raum zum Atmen und spüre mehr Weite im Oberkörper.','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 21:06:16.046','2026-05-09 21:06:16.046'),(18,25,'im-gleichgewicht-information-de','Im Gleichgewicht','Lange einbeinige Balancen wechseln sich mit Brustöffnungen und Twists ab. Eine leicht fordernde Praxis, die dich klar im Körper verankert und deinen Geist sammelt.','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 21:07:40.703','2026-05-09 21:07:40.703'),(19,26,'achtsam-entschleunigen-information-de','Achtsam entschleunigen','Dieser ruhiger Flow unterstützt dich dabei runterzufahren und auf deinen eigenen Körper zu hören. Sanfte Dehnungen im Stehen und im Sitzen schenken dir wohltuende Ruhe und Entspannung.','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 21:09:22.395','2026-05-09 21:09:22.395'),(20,27,'kraft-und-entspannung-fuer-den-unterkoerper-information-de','Kraft und Entspannung für den Unterkörper','Diese Einheit verbindet länger gehaltene Posen für den Unterkörper mit aktivierenden Sequenzen für deine Körpermitte. So baust du Kraft auf und kommst zugleich angenehm zur Ruhe.','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 21:11:06.889','2026-05-09 21:11:06.889'),(21,28,'zeit-zum-oeffnen-information-de','Zeit zum Öffnen','Ein langsamer Flow, der deiner Atmung und jeder Haltung bewusst mehr Raum schenkt. Dehne deinen ganzen Körper, verlangsame deine Atmung, und lass deinen Geist ruhiger werden.','Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum Lorem Larum Ipsum','de','2026-05-09 21:11:38.587','2026-05-09 21:11:38.587');
